 10â†’private val LOGGER = KotlinLogging.logger {}.initKtLintKLogger()
 11â†’
 12â†’/**
 13â†’ * Sorts the [RuleProvider]s based on [Rule.VisitorModifier]s.
 14â†’ */
 15â†’internal class RuleProviderSorter {
 16â†’    /**
 17â†’     * Prevent duplicate debug logging whenever the same set of [Rule.id]s (but not the same instance) are sorted. As
 18â†’     * the sorting of the [RuleProvider] has to be executed for each file.
 19â†’     */
 20â†’    private val debugLogCache = mutableMapOf<Int, Boolean>()
 21â†’
 22â†’    @Synchronized
 23â†’    fun getSortedRuleProviders(ruleProviders: Set<RuleProvider>): List<RuleProvider> =
 24â†’        ruleProviders
 25â†’            .sort()
 26â†’            .also { sortedRuleProviders ->
 27â†’                if (LOGGER.isDebugEnabled) {
 28â†’                    logSortedRuleProviders(sortedRuleProviders)
 29â†’                }
 30â†’            }
 31â†’
 32â†’    private fun logSortedRuleProviders(sortedRuleProviders: List<RuleProvider>) {
 33â†’        debugLogCache
 34â†’            .putIfAbsent(createHashCode(sortedRuleProviders), true)
 35â†’            .also { previousValue ->
 36â†’                if (previousValue == null) {
 37â†’                    // Logging was not printed for this combination of rule providers as no entry was found in the cache
 38â†’                    sortedRuleProviders
 39â†’                        .joinToString(prefix = "Rules will be executed in order below:") {
 40â†’                            "\n           - ${it.ruleId.value}"
 41â†’                        }.also { LOGGER.debug(it) }
 42â†’                }
 43â†’            }
 44â†’    }
 45â†’
 46â†’    private fun createHashCode(sortedRuleProviders: List<RuleProvider>): Int =
 47â†’        sortedRuleProviders
 48â†’            .joinToString(
 49â†’                prefix = "rule-ids=[",
 50â†’                separator = ",",
 51â†’                postfix = "]",
 52â†’            ) { it.ruleId.value }
 53â†’            .hashCode()
 54â†’
 55â†’    private fun Set<RuleProvider>.sort(): List<RuleProvider> {
 56â†’        forEach { ruleProvider ->
 57â†’            ruleProvider.hasNoVisitorModifierReferringToSelf()
 58â†’        }
 59â†’
 60â†’        val ruleIdsToBeSorted = map { it.ruleId }.toSet()
 61â†’        val unprocessedRuleProviders =
 62â†’            sortedWith(defaultRuleExecutionOrderComparator())
 63â†’                .toMutableList()
 64â†’        val sortedRuleProviders = mutableListOf<RuleProvider>()
 65â†’        val ruleIdsSortedRuleProviders = mutableSetOf<RuleId>()
 66â†’
 67â†’        // Initially the list only contains the rules not depending on another rule.
 68â†’        unprocessedRuleProviders
 69â†’            .filter { !it.runAsLateAsPossible && it.hasNoRunAfterRules() }
 70â†’            .forEach { ruleProvider ->
 71â†’                sortedRuleProviders.add(ruleProvider)
 72â†’                ruleIdsSortedRuleProviders.add(ruleProvider.ruleId)
 73â†’            }
 74â†’        unprocessedRuleProviders.removeAll(sortedRuleProviders)
 75â†’        while (unprocessedRuleProviders.isNotEmpty()) {
 76â†’            val ruleProvider =
 77â†’                unprocessedRuleProviders
 78â†’                    .firstOrNull { ruleProvider ->
 79â†’                        ruleProvider
 80â†’                            .runAfterRules
 81â†’                            .filter { it.ruleId in ruleIdsToBeSorted }
 82â†’                            .all { it.ruleId in ruleIdsSortedRuleProviders }
 83â†’                    }
 84â†’                    ?: throw IllegalStateException(
 85â†’                        "Can not complete sorting of rule providers as next item can not be determined.",
 86â†’                    )
 87â†’            sortedRuleProviders.add(ruleProvider)
 88â†’            ruleIdsSortedRuleProviders.add(ruleProvider.ruleId)
 89â†’            unprocessedRuleProviders.remove(ruleProvider)
 90â†’        }
 91â†’        return sortedRuleProviders
 92â†’    }
 93â†’
 94â†’    private fun RuleProvider.hasNoVisitorModifierReferringToSelf() {
 95â†’        runAfterRules.forEach { runAfterRuleVisitorModifier ->
 96â†’            check(ruleId != runAfterRuleVisitorModifier.ruleId) {
 97â†’                "Rule with id '${ruleId.value}' has a visitor modifier of type '${Rule.VisitorModifier.RunAfterRule::class.simpleName}' " +
 98â†’                    "which may not refer to the rule itself."
 99â†’            }
100â†’        }
101â†’    }
102â†’
103â†’    private fun defaultRuleExecutionOrderComparator() =
104â†’        // The sort order below should guarantee a stable order of the rule between multiple invocations of KtLint given
105â†’        // the same set of input parameters. There should be no dependency on data ordering outside this class.
106â†’        compareBy<RuleProvider> {
107â†’            if (it.runAsLateAsPossible) {
108â†’                1
109â†’            } else {
110â†’                0
111â†’            }
112â†’        }.thenBy {
113â†’            if (it.ruleId.ruleSetId == RuleSetId.STANDARD) {
114â†’                0
115â†’            } else {
116â†’                1
117â†’            }
118â†’        }.thenBy { it.ruleId.value }
119â†’
120â†’    private fun RuleProvider.hasNoRunAfterRules() = runAfterRules.isEmpty()
