{"file_path":"/project/ktlint-rule-engine/src/test/kotlin/com/pinterest/ktlint/rule/engine/api/KtLintRuleEngineFormatRerunTest.kt","content":"package com.pinterest.ktlint.rule.engine.api

import com.pinterest.ktlint.rule.engine.core.api.ElementType.REGULAR_STRING_PART
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.Rule.VisitorModifier.RunAsLateAsPossible
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.EditorConfig
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test

class KtLintRuleEngineFormatRerunTest {
    @BeforeEach
    fun setUp() {
        ConvertBarToBazRule.reset()
        ConvertFooToBarRule.reset()
        FlipFlopRule.reset()
    }

    @Test
    fun `format reruns until no autocorrectable errors remain`() {
        val callbackResults = mutableListOf<Pair<String, Boolean>>()
        val formattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { ConvertBarToBazRule() },
                        RuleProvider { ConvertFooToBarRule() },
                    ),
            ).format(
                Code.fromSnippet(
                    """
                    val value = "foo"
                    """.trimIndent(),
                ),
            ) { lintError, corrected ->
                callbackResults.add(lintError.detail to corrected)
            }

        assertThat(formattedCode).isEqualTo(
            """
            val value = "baz"
            """.trimIndent(),
        )
        assertThat(callbackResults).isEmpty()
        assertThat(ConvertBarToBazRule.invocationCount).isEqualTo(3)
        assertThat(ConvertFooToBarRule.invocationCount).isEqualTo(3)
    }

    @Test
    fun `format stops rerunning after reaching maximum rerun limit`() {
        val callbackResults = mutableListOf<Boolean>()
        val formattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { FlipFlopRule() },
                    ),
            ).format(
                Code.fromSnippet(
                    """
                    val value = "foo"
                    """.trimIndent(),
                ),
            ) { _, corrected ->
                callbackResults.add(corrected)
            }

        assertThat(FlipFlopRule.invocationCount).isEqualTo(KtLintRuleEngine.MAX_FORMAT_RERUNS + 1)
        assertThat(callbackResults)
            .hasSize(1)
            .allMatch { it }
        assertThat(formattedCode).isEqualTo(
            """
            val value = "foo"
            """.trimIndent(),
        )
    }
}

private class ConvertBarToBazRule : Rule(
    ruleId = RuleId("test:convert-bar-to-baz"),
    about = About(),
) {
    override fun beforeFirstNode(editorConfig: EditorConfig) {
        incrementInvocationCount()
    }

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART && node.text == "bar") {
            emit(node.startOffset, "bar should be turned into baz", true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText("baz")
            }
        }
    }

    companion object {
        private var invocationCounter = 0

        internal fun reset() {
            invocationCounter = 0
        }

        internal fun incrementInvocationCount() {
            invocationCounter++
        }

        internal val invocationCount: Int
            get() = invocationCounter
    }
}

private class ConvertFooToBarRule : Rule(
    ruleId = RuleId("test:convert-foo-to-bar"),
    about = About(),
    visitorModifiers = setOf(RunAsLateAsPossible),
) {
    override fun beforeFirstNode(editorConfig: EditorConfig) {
        incrementInvocationCount()
    }

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART && node.text == "foo") {
            emit(node.startOffset, "foo should be turned into bar", true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText("bar")
            }
        }
    }

    companion object {
        private var invocationCounter = 0

        internal fun reset() {
            invocationCounter = 0
        }

        internal fun incrementInvocationCount() {
            invocationCounter++
        }

        internal val invocationCount: Int
            get() = invocationCounter
    }
}

private class FlipFlopRule : Rule(
    ruleId = RuleId("test:flip-flop"),
    about = About(),
) {
    override fun beforeFirstNode(editorConfig: EditorConfig) {
        incrementInvocationCount()
    }

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType != REGULAR_STRING_PART) {
            return
        }
        when (node.text) {
            "foo" -> {
                emit(node.startOffset, "foo toggled to bar", true)
                if (autoCorrect) {
                    (node as LeafElement).rawReplaceWithText("bar")
                }
            }
            "bar" -> {
                emit(node.startOffset, "bar toggled to foo", true)
                if (autoCorrect) {
                    (node as LeafElement).rawReplaceWithText("foo")
                }
            }
        }
    }

    companion object {
        private var invocationCounter = 0

        internal fun reset() {
            invocationCounter = 0
        }

        internal fun incrementInvocationCount() {
            invocationCounter++
        }

        internal val invocationCount: Int
            get() = invocationCounter
    }
}
"}

