            val formatRunResult = performFormatRun(code, ruleExecutionContext, visitorProvider)

            finalErrors = formatRunResult.lintErrors
            anyMutationsApplied = anyMutationsApplied || formatRunResult.mutated

            shouldRerun =
                formatRunResult.hasAutoCorrectableErrors && rerunsExecuted < MAX_FORMAT_RERUNS
            if (shouldRerun) {
                rerunsExecuted++
                LOGGER.debug {
                    "Rerunning format for file '${code.fileNameOrStdin()}' (rerun $rerunsExecuted of $MAX_FORMAT_RERUNS)"
                }
