        if (node.elementType == REGULAR_STRING_PART && node.text == "foo") {
            emit(node.startOffset, "foo should be turned into bar", true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText("bar")
                incrementAutoCorrectCount()
            }
        }
    }

    companion object {
        private var autoCorrectCounter = 0

        internal fun reset() {
            autoCorrectCounter = 0
        }

        internal fun incrementAutoCorrectCount() {
            autoCorrectCounter++
        }

        internal val autoCorrectCount: Int
            get() = autoCorrectCounter
    }
}

private class FlipFlopRule : Rule(
    ruleId = RuleId("test:flip-flop"),
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType != REGULAR_STRING_PART) {
            return
        }
        when (node.text) {
            "foo" -> {
                emit(node.startOffset, "foo toggled to bar", true)
                if (autoCorrect) {
                    (node as LeafElement).rawReplaceWithText("bar")
                    incrementAutoCorrectCount()
                }
            }
            "bar" -> {
                emit(node.startOffset, "bar toggled to foo", true)
                if (autoCorrect) {
                    (node as LeafElement).rawReplaceWithText("foo")
                    incrementAutoCorrectCount()
                }
            }
        }
    }

    companion object {
        private var autoCorrectCounter = 0

        internal fun reset() {
            autoCorrectCounter = 0
        }

        internal fun incrementAutoCorrectCount() {
            autoCorrectCounter++
        }

        internal val autoCorrectCount: Int
            get() = autoCorrectCounter
    }
}
